/**
 * Page Builder Toolbar - Top Action Bar
 * Purpose: Main actions like save, preview, publish
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

'use client';

import React from 'react';

interface ToolbarProps {
  onSave: () => Promise<void>;
  isSaving: boolean;
  isPreviewMode: boolean;
  onTogglePreview: () => void;
  previewMode: 'desktop' | 'tablet' | 'mobile';
  onPreviewModeChange: (mode: 'desktop' | 'tablet' | 'mobile') => void;
  pageId?: string;
  pageStatus?: string;
  onPublish?: () => Promise<void>;
  isSectionLibraryVisible?: boolean;
  onToggleSectionLibrary?: () => void;
  onOpenJSONEditor?: () => void;
}

export function Toolbar({
  onSave,
  isSaving,
  isPreviewMode,
  onTogglePreview,
  previewMode,
  onPreviewModeChange,
  pageId,
  pageStatus,
  onPublish,
  isSectionLibraryVisible = true,
  onToggleSectionLibrary,
  onOpenJSONEditor,
}: ToolbarProps) {
  const [isPublishing, setIsPublishing] = React.useState(false);

  const handlePublish = async () => {
    if (!pageId) return;
    
    setIsPublishing(true);
    try {
      const token = localStorage.getItem('adminToken');
      const res = await fetch(`/api/admin/pages/${pageId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ status: 'published' })
      });

      const result = await res.json();
      console.log('Publish result:', result);

      if (res.ok && result.success) {
        if (onPublish) await onPublish();
        alert('Page published successfully!');
        window.location.reload();
      } else {
        alert('Failed to publish: ' + (result.error || 'Unknown error'));
      }
    } catch (err) {
      console.error('Publish error:', err);
      alert('Failed to publish page');
    } finally {
      setIsPublishing(false);
    }
  };
  return (
    <div className="h-auto min-h-16 bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 flex flex-col sm:flex-row items-stretch sm:items-center justify-between px-3 sm:px-6 py-2 sm:py-0 gap-2 sm:gap-0">
      {/* Left Section - Page Info & Toggle */}
      <div className="flex items-center space-x-2 sm:space-x-4">
        {/* Section Library Toggle */}
        {onToggleSectionLibrary && !isPreviewMode && (
          <button
            onClick={onToggleSectionLibrary}
            className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
            title={isSectionLibraryVisible ? 'Hide Section Library' : 'Show Section Library'}
          >
            {isSectionLibraryVisible ? (
              <svg className="w-5 h-5 text-gray-700 dark:text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 19l-7-7 7-7m8 14l-7-7 7-7" />
              </svg>
            ) : (
              <svg className="w-5 h-5 text-gray-700 dark:text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
              </svg>
            )}
          </button>
        )}
        
        <h1 className="text-base sm:text-lg font-semibold text-gray-900 dark:text-white">
          Page Builder
        </h1>
        <div className="text-xs sm:text-sm text-gray-500 dark:text-gray-400">
          Visual Editor
        </div>
      </div>

      {/* Center Section - Device Preview */}
      {!isPreviewMode && (
        <div className="flex items-center space-x-1 bg-gray-100 dark:bg-gray-700 rounded-lg p-1">
          {[
            { mode: 'desktop' as const, icon: '🖥️', label: 'Desktop' },
            { mode: 'tablet' as const, icon: '📱', label: 'Tablet' },
            { mode: 'mobile' as const, icon: '📱', label: 'Mobile' },
          ].map(({ mode, icon, label }) => (
            <button
              key={mode}
              onClick={() => onPreviewModeChange(mode)}
              className={`px-2 sm:px-3 py-1.5 sm:py-2 rounded-md text-xs sm:text-sm font-medium transition-colors ${
                previewMode === mode
                  ? 'bg-white dark:bg-gray-600 text-gray-900 dark:text-white shadow-sm'
                  : 'text-gray-600 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white'
              }`}
              title={label}
            >
              <span className="mr-1 sm:mr-2">{icon}</span>
              <span className="hidden md:inline">{label}</span>
            </button>
          ))}
        </div>
      )}

      {/* Right Section - Actions */}
      <div className="flex items-center space-x-2 sm:space-x-3">
        {/* JSON Editor Button */}
        {onOpenJSONEditor && !isPreviewMode && (
          <button
            onClick={onOpenJSONEditor}
            className="px-3 sm:px-4 py-1.5 sm:py-2 bg-purple-600 hover:bg-purple-700 text-white rounded-lg text-xs sm:text-sm font-medium transition-colors flex items-center"
            title="Edit Page JSON"
          >
            <svg className="w-4 h-4 mr-1 sm:mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
            </svg>
            <span className="hidden sm:inline">JSON</span>
          </button>
        )}

        {/* Preview Toggle */}
        <button
          onClick={onTogglePreview}
          className={`px-3 sm:px-4 py-1.5 sm:py-2 rounded-lg text-xs sm:text-sm font-medium transition-colors ${
            isPreviewMode
              ? 'bg-blue-600 text-white hover:bg-blue-700'
              : 'bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
          }`}
        >
          {isPreviewMode ? (
            <>
              <span className="mr-1 sm:mr-2">✏️</span>
              <span className="hidden sm:inline">Edit</span>
            </>
          ) : (
            <>
              <span className="mr-1 sm:mr-2">👁️</span>
              <span className="hidden sm:inline">Preview</span>
            </>
          )}
        </button>

        {/* Save Button */}
        <button
          onClick={onSave}
          disabled={isSaving}
          className="px-3 sm:px-4 py-1.5 sm:py-2 bg-green-600 hover:bg-green-700 disabled:bg-green-400 text-white rounded-lg text-xs sm:text-sm font-medium transition-colors flex items-center"
        >
          {isSaving ? (
            <>
              <div className="animate-spin rounded-full h-3 w-3 sm:h-4 sm:w-4 border-2 border-white border-t-transparent mr-1 sm:mr-2" />
              <span className="hidden sm:inline">Saving...</span>
            </>
          ) : (
            <>
              <span className="mr-1 sm:mr-2">💾</span>
              <span className="hidden sm:inline">Save</span>
            </>
          )}
        </button>

        {/* Publish Button */}
        <button
          onClick={handlePublish}
          disabled={isPublishing || pageStatus === 'published'}
          className="px-3 sm:px-4 py-1.5 sm:py-2 bg-violet-600 hover:bg-violet-700 disabled:bg-gray-400 text-white rounded-lg text-xs sm:text-sm font-medium transition-colors flex items-center"
        >
          {isPublishing ? (
            <>
              <div className="animate-spin rounded-full h-3 w-3 sm:h-4 sm:w-4 border-2 border-white border-t-transparent mr-1 sm:mr-2" />
              <span className="hidden sm:inline">Publishing...</span>
            </>
          ) : pageStatus === 'published' ? (
            <>
              <span className="mr-1 sm:mr-2">✅</span>
              <span className="hidden sm:inline">Published</span>
            </>
          ) : (
            <>
              <span className="mr-1 sm:mr-2">🚀</span>
              <span className="hidden sm:inline">Publish</span>
            </>
          )}
        </button>
      </div>
    </div>
  );
}